import React, { createContext, useContext, useState, useEffect } from 'react';

const CartContext = createContext();

export const CartProvider = ({ children }) => {
    const [cart, setCart] = useState(() => {
        // Recuperamos el carrito guardado en la nube local del navegador
        const savedCart = localStorage.getItem('cart_ofertas_v1');
        return savedCart ? JSON.parse(savedCart) : [];
    });

    // Sincronización automática con LocalStorage cada vez que cambia el carrito
    useEffect(() => {
        localStorage.setItem('cart_ofertas_v1', JSON.stringify(cart));
    }, [cart]);

    const addToCart = (producto) => {
        setCart((prevCart) => {
            const itemExists = prevCart.find((item) => item._id === producto._id);
            if (itemExists) {
                // Si ya existe, verificamos que no supere el stock disponible
                return prevCart.map((item) =>
                    item._id === producto._id 
                        ? { ...item, cantidad: Math.min(item.cantidad + 1, item.stock) } 
                        : item
                );
            }
            // Agregamos el producto nuevo con cantidad inicial 1
            return [...prevCart, { ...producto, cantidad: 1 }];
        });
    };

    const removeFromCart = (id) => {
        setCart((prevCart) => prevCart.filter((item) => item._id !== id));
    };

    const updateQuantity = (id, newQty) => {
        if (newQty < 1) return;
        setCart((prevCart) =>
            prevCart.map((item) => {
                if (item._id === id) {
                    // Validamos contra el stock real del producto
                    const cantFinal = Math.min(newQty, item.stock);
                    return { ...item, cantidad: cantFinal };
                }
                return item;
            })
        );
    };

    const clearCart = () => setCart([]);

    // --- CÁLCULOS DERIVADOS ---
    const totalItems = cart.reduce((acc, item) => acc + item.cantidad, 0);
    const totalPrice = cart.reduce((acc, item) => acc + (item.precioNuevo * item.cantidad), 0);

    return (
        <CartContext.Provider value={{ 
            cart, 
            addToCart, 
            removeFromCart, 
            updateQuantity,
            clearCart, 
            // Exportamos con los nombres que usan tus componentes visuales
            count: totalItems, 
            total: totalPrice,
            // También dejamos los originales por si los usas en otro lado
            totalItems, 
            totalPrice 
        }}>
            {children}
        </CartContext.Provider>
    );
};

export const useCart = () => {
    const context = useContext(CartContext);
    if (!context) {
        throw new Error("useCart debe ser usado dentro de un CartProvider");
    }
    return context;
};
